let
  waybar-weather = pkgs.writeShellScriptBin "waybar-weather" ''
        set -euo pipefail

        json=$(${pkgs.curl}/bin/curl -sf --max-time 10 "wttr.in/?format=j1" 2>/dev/null) || {
