        # Scan today's hourly forecast for upcoming precipitation
        current_hour=$(date +%H)
        forecast=""
        upcoming=$(echo "$json" | ${pkgs.jq}/bin/jq -r --argjson h "$current_hour" '
          [.weather[0].hourly[] |
