            176|263|266|293|296|299|302|305|308|353|356|359)
              if [ -z "$forecast" ]; then
                forecast="Rain expected later"
                forecast_icon="َ°–—"
              fi ;;
          esac
        done

        # Build display text
        text="$icon $tempآ°C"
        if [ -n "$forecast" ]; then
          text="$text â†’ $forecast_icon"
        fi

        # Build tooltip
        tooltip="$desc
    Feels like ''${feels}آ°C
    Humidity: ''${humidity}%"
        if [ -n "$forecast" ]; then
          tooltip="$tooltip

    $forecast"
        fi

        ${pkgs.jq}/bin/jq -nc \
          --arg text "$text" \
          --arg tooltip "$tooltip" \
          '{"text": $text, "tooltip": $tooltip}'
  '';
